'use strict';const running=require('./running'),gearing=require('./gear');$(document).ready(function(){$("[name='cadence']").change(function(){$("#calculator_gearing").submit()}),$("#calculator_gearing").submit(function(b){console.log("Calculate gearing"),b.preventDefault();let c=Number($("[name='wheel_diameter']").val()),d=Number($("[name='klinge']").val()),e=Number($("[name='gearhjul']").val()),f=Number($("[name='cadence']").val()),a=gearing.Gearing(c,d,e);$("#geartal").val(a.getGearTal().toFixed(0)),$("#meter_per_round").val(a.getMeterPerRound().toFixed(1)),$("#velocity_at_cadence").val(a.getVelocityAtCadence(f).toFixed(2))}),$("#calculator_velocity").submit(function(a){console.log("Calculate velocity"),a.preventDefault();let b=Number($("[name='min']").val()),c=Number($("[name='sec']").val()),d=Number($("[name='distance']").val()),e=running.Running();$("#velocity_kmt").val(e.getKilometersPrHour(b,c,d).toFixed(2))}),$("#calculator_velocity_distance").submit(function(a){console.log("Calculate distance"),a.preventDefault();let b=Number($("[name='dist_min']").val()),c=Number($("[name='dist_sec']").val()),d=Number($("[name='dist_velocity']").val()),e=running.Running();$("#dist_distance").val(e.getDistanceFromTimeAndVelocity(b,c,d).toFixed(1))}),$("#calculator_velocity_time").submit(function(c){console.log("Calculate time"),c.preventDefault();let d=Number($("[name='time_distance']").val()),e=Number($("[name='time_velocity']").val()),f=running.Running(),a=f.getTimeFromDistanceAndVelocity(d,e),b=Math.floor(a),g=(a-b)*60;$("[name='time_min']").val(b),$("[name='time_sec']").val(g.toFixed(0))})})